def floor_tile_class(mask, x, y):
    """Deterministic variant pick so the floor looks varied but stable."""
    variants = FLOOR_VARIANTS.get(mask) or FLOOR_VARIANTS[1]
    return variants[(x * 7 + y * 13) % len(variants)]


def map_tiles_css():
    """CSS block defining every tile class. Injected ONCE into the HTML
    shell (wrap_html) so per-move render payloads stay tiny -- cells only
    carry a class name."""
    rules = [
        ".zmap-cell.mt { background-size: 100% 100%; "
        "image-rendering: pixelated; border-radius: 3px; }"
    ]
    for cls, b64 in TILE_B64.items():
        rules.append(
            f".zmap-cell.{cls} {{ background-image: "
            f"url(data:image/webp;base64,{b64}); }}"
        )
    return "\n".join(rules)
